{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01T9ZJ9rsyuBAxUhf95ygsVX","type":"tool_result","content":"0\tuse std::future::Future;\n1\tuse std::time::{SystemTime, UNIX_EPOCH};\n2\t\n3\tuse tokio_postgres::NoTls;\n4\t\n5\tuse axon_audit::entry::AuditEntry;\n6\tuse axon_core::error::AxonError;\n7\tuse axon_core::id::{\n8\t    CollectionId, EntityId, Namespace, QualifiedCollectionId, DEFAULT_DATABASE, DEFAULT_SCHEMA,\n9\t};\n10\tuse axon_core::types::Entity;\n11\tuse axon_schema::schema::{CollectionSchema, CollectionView};\n12\t\n13\tuse crate::adapter::StorageAdapter;\n14\t\n15\t/// PostgreSQL-backed storage adapter.\n16\t///\n17\t/// Uses the asynchronous `tokio-postgres` crate driven from a dedicated Tokio\n18\t/// runtime. Because `StorageAdapter` is synchronous, each database call\n19\t/// blocks the calling thread via `handle.block_on(...)`.\n20\t///\n21\t/// Transactions are handled via `BEGIN` / `COMMIT` / `ROLLBACK` statements.\n22\t/// The adapter creates the required tables on initialization if they do not\n23\t/// exist.\n24\tpub struct PostgresStorageAdapter {\n25\t    client: tokio_postgres::Client,\n26\t    handle: tokio::runtime::Handle,\n27\t    _rt: tokio::runtime::Runtime,\n28\t    in_tx: bool,\n29\t}\n30\t\n31\timpl PostgresStorageAdapter {\n32\t    /// Connect to a PostgreSQL database using a connection string.\n33\t    ///\n34\t    /// Example: `\"host=localhost user=axon dbname=axon\"`\n35\t    pub fn connect(params: &str) -> Result<Self, AxonError> {\n36\t        let rt = tokio::runtime::Builder::new_multi_thread()\n37\t            .worker_threads(2)\n38\t            .enable_all()\n39\t            .build()\n40\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\n41\t        let handle = rt.handle().clone();\n42\t        let (client, connection) = handle\n43\t            .block_on(tokio_postgres::connect(params, NoTls))\n44\t            .map_err(|e| AxonError::Storage(format!(\"connection failed: {e}\")))?;\n45\t        handle.spawn(async move {\n46\t            if let Err(e) = connection.await {\n47\t                tracing::error!(\"postgres connection error: {e}\");\n48\t            }\n49\t        });\n50\t        let mut adapter = Self {\n51\t            client,\n52\t            handle,\n53\t            _rt: rt,\n54\t            in_tx: false,\n55\t        };\n56\t        adapter.init_schema()?;\n57\t        Ok(adapter)\n58\t    }\n59\t\n60\t    /// Block the current thread on a `tokio_postgres` future, converting any\n61\t    /// error into `AxonError::Storage`.\n62\t    ///\n63\t    /// When called from within a Tokio async task, uses\n64\t    /// [`tokio::task::block_in_place`] to temporarily un-enter the async\n65\t    /// context before blocking on the adapter's dedicated runtime.  This\n66\t    /// prevents the \"cannot call `block_on` from within an async context\"\n67\t    /// panic that would otherwise occur when gateway route handlers drive\n68\t    /// storage calls.\n69\t    ///\n70\t    /// Requires the multi-thread Tokio scheduler (used by the production\n71\t    /// server).  Tests that use the default `current_thread` scheduler must\n72\t    /// call adapter methods from a `spawn_blocking` closure.\n73\t    fn block<T>(\n74\t        &self,\n75\t        fut: impl Future<Output = Result<T, tokio_postgres::Error>>,\n76\t    ) -> Result<T, AxonError> {\n77\t        match tokio::runtime::Handle::try_current() {\n78\t            Ok(_) => tokio::task::block_in_place(|| self.handle.block_on(fut)),\n79\t            Err(_) => self.handle.block_on(fut),\n80\t        }\n81\t        .map_err(|e| AxonError::Storage(e.to_string()))\n82\t    }\n83\t\n84\t    fn init_schema(&mut self) -> Result<(), AxonError> {\n85\t        self.block(self.client.batch_execute(\n86\t            \"CREATE TABLE IF NOT EXISTS databases (\n87\t                    name TEXT NOT NULL PRIMARY KEY\n88\t                );\n89\t                CREATE TABLE IF NOT EXISTS namespaces (\n90\t                    database_name TEXT NOT NULL REFERENCES databases(name) ON DELETE CASCADE,\n91\t                    name          TEXT NOT NULL,\n92\t                    PRIMARY KEY (database_name, name)\n93\t                );\n94\t                CREATE TABLE IF NOT EXISTS entities (\n95\t                    collection    TEXT NOT NULL,\n96\t                    database_name TEXT NOT NULL DEFAULT 'default',\n97\t                    schema_name   TEXT NOT NULL DEFAULT 'default',\n98\t                    id            TEXT NOT NULL,\n99\t                    version       BIGINT NOT NULL,\n100\t                    data          JSONB NOT NULL,\n101\t                    PRIMARY KEY (database_name, schema_name, collection, id)\n102\t                );\n103\t                CREATE TABLE IF NOT EXISTS schemas (\n104\t                    collection    TEXT NOT NULL,\n105\t                    database_name TEXT NOT NULL DEFAULT 'default',\n106\t                    schema_name   TEXT NOT NULL DEFAULT 'default',\n107\t                    version       INTEGER NOT NULL,\n108\t                    schema_json   JSONB NOT NULL,\n109\t                    created_at_ns BIGINT NOT NULL DEFAULT 0,\n110\t                    PRIMARY KEY (database_name, schema_name, collection, version)\n111\t                );\n112\t                CREATE TABLE IF NOT EXISTS collections (\n113\t                    name TEXT NOT NULL,\n114\t                    database_name TEXT NOT NULL DEFAULT 'default',\n115\t                    schema_name TEXT NOT NULL DEFAULT 'default',\n116\t                    PRIMARY KEY (database_name, schema_name, name)\n117\t                );\n118\t                CREATE TABLE IF NOT EXISTS collection_views (\n119\t                    collection    TEXT NOT NULL,\n120\t                    database_name TEXT NOT NULL DEFAULT 'default',\n121\t                    schema_name   TEXT NOT NULL DEFAULT 'default',\n122\t                    version       INTEGER NOT NULL,\n123\t                    view_json     JSONB NOT NULL,\n124\t                    updated_at_ns BIGINT NOT NULL,\n125\t                    updated_by    TEXT,\n126\t                    PRIMARY KEY (database_name, schema_name, collection),\n127\t                    FOREIGN KEY (database_name, schema_name, collection)\n128\t                        REFERENCES collections(database_name, schema_name, name)\n129\t                        ON DELETE CASCADE\n130\t                );\n131\t                CREATE TABLE IF NOT EXISTS audit_log (\n132\t                    id             BIGSERIAL PRIMARY KEY,\n133\t                    timestamp_ns   BIGINT NOT NULL,\n134\t                    collection     TEXT NOT NULL,\n135\t                    entity_id      TEXT NOT NULL,\n136\t                    version        BIGINT NOT NULL,\n137\t                    mutation       TEXT NOT NULL,\n138\t                    actor          TEXT NOT NULL,\n139\t                    transaction_id TEXT,\n140\t                    entry_json     JSONB NOT NULL\n141\t                );\",\n142\t        ))?;\n143\t        self.ensure_namespace_catalog_tables()?;\n144\t        self.ensure_default_namespace()\n145\t    }\n146\t\n147\t    fn collection_exists_in_namespace(\n148\t        &self,\n149\t        collection: &CollectionId,\n150\t        namespace: &Namespace,\n151\t    ) -> Result<bool, AxonError> {\n152\t        let row = self.block(self.client.query_one(\n153\t            \"SELECT EXISTS(\n154\t                    SELECT 1 FROM collections\n155\t                    WHERE name = $1 AND database_name = $2 AND schema_name = $3\n156\t                )\",\n157\t            &[&collection.as_str(), &namespace.database, &namespace.schema],\n158\t        ))?;\n159\t        Ok(row.get(0))\n160\t    }\n161\t\n162\t    fn database_exists(&self, database: &str) -> Result<bool, AxonError> {\n163\t        let row = self.block(self.client.query_one(\n164\t            \"SELECT EXISTS(SELECT 1 FROM databases WHERE na