          ALTER TABLE schemas\n206\t                     ADD COLUMN IF NOT EXISTS database_name TEXT NOT NULL DEFAULT 'default';\n207\t                 ALTER TABLE schemas\n208\t                     ADD COLUMN IF NOT EXISTS schema_name TEXT NOT NULL DEFAULT 'default';\n209\t                 ALTER TABLE schemas\n210\t                     ADD COLUMN IF NOT EXISTS created_at_ns BIGINT NOT NULL DEFAULT 0;\n211\t                 ALTER TABLE collection_views\n212\t                     ADD COLUMN IF NOT EXISTS database_name TEXT NOT NULL DEFAULT 'default';\n213\t                 ALTER TABLE collection_views\n214\t                     ADD COLUMN IF NOT EXISTS schema_name TEXT NOT NULL DEFAULT 'default';\",\n215\t        ))?;\n216\t\n217\t        if self.table_pk_columns(\"entities\")?\n218\t            != vec![\"database_name\", \"schema_name\", \"collection\", \"id\"]\n219\t        {\n220\t            self.block(self.client.batch_execute(\n221\t                \"ALTER TABLE entities DROP CONSTRAINT IF EXISTS entities_pkey;\n222\t                     ALTER TABLE entities ADD PRIMARY KEY (database_name, schema_name, collection, id);\",\n223\t            ))?;\n224\t        }\n225\t\n226\t        self.block(self.client.execute(\n227\t            \"UPDATE schemas s\n228\t                 SET database_name = c.database_name,\n229\t                     schema_name = c.schema_name\n230\t                 FROM collections c\n231\t                 WHERE s.collection = c.name\n232\t                   AND (s.database_name = 'default' OR s.schema_name = 'default')\",\n233\t            &[],\n234\t        ))?;\n235\t        self.block(self.client.execute(\n236\t            \"UPDATE collection_views v\n237\t                 SET database_name = c.database_name,\n238\t                     schema_name = c.schema_name\n239\t                 FROM collections c\n240\t                 WHERE v.collection = c.name\n241\t                   AND (v.database_name = 'default' OR v.schema_name = 'default')\",\n242\t            &[],\n243\t        ))?;\n244\t\n245\t        if self.table_pk_columns(\"collections\")? != vec![\"database_name\", \"schema_name\", \"name\"] {\n246\t            self.block(self.client.batch_execute(\n247\t                \"ALTER TABLE collection_views DROP CONSTRAINT IF EXISTS collection_views_collection_fkey;\n248\t                     ALTER TABLE collection_views DROP CONSTRAINT IF EXISTS collection_views_pkey;\n249\t                     ALTER TABLE collections DROP CONSTRAINT IF EXISTS collections_pkey;\n250\t                     ALTER TABLE collections ADD PRIMARY KEY (database_name, schema_name, name);\",\n251\t            ))?;\n252\t        }\n253\t\n254\t        if self.table_pk_columns(\"schemas\")?\n255\t            != vec![\"database_name\", \"schema_name\", \"collection\", \"version\"]\n256\t        {\n257\t            self.block(self.client.batch_execute(\n258\t                \"ALTER TABLE schemas DROP CONSTRAINT IF EXISTS schemas_pkey;\n259\t                     ALTER TABLE schemas\n260\t                         ADD PRIMARY KEY (database_name, schema_name, collection, version);\",\n261\t            ))?;\n262\t        }\n263\t\n264\t        if self.table_pk_columns(\"collection_views\")?\n265\t            != vec![\"database_name\", \"schema_name\", \"collection\"]\n266\t        {\n267\t            self.block(self.client.batch_execute(\n268\t                \"ALTER TABLE collection_views DROP CONSTRAINT IF EXISTS collection_views_pkey;\n269\t                     ALTER TABLE collection_views ADD PRIMARY KEY (database_name, schema_name, collection);\",\n270\t            ))?;\n271\t        }\n272\t\n273\t        self.block(self.client.batch_execute(\n274\t            \"ALTER TABLE collection_views DROP CONSTRAINT IF EXISTS collection_views_collection_fkey;\n275\t                 ALTER TABLE collection_views\n276\t                     ADD CONSTRAINT collection_views_collection_fkey\n277\t                     FOREIGN KEY (database_name, schema_name, collection)\n278\t                     REFERENCES collections(database_name, schema_name, name)\n279\t                     ON DELETE CASCADE;\n280\t                 CREATE INDEX IF NOT EXISTS idx_collections_namespace\n281\t                     ON collections (database_name, schema_name, name);\",\n282\t        ))?;\n283\t        Ok(())\n284\t    }\n285\t\n286\t    fn registered_collection_namespaces(\n287\t        &self,\n288\t        collection: &CollectionId,\n289\t    ) -> Result<Vec<Namespace>, AxonError> {\n290\t        let rows = self.block(self.client.query(\n291\t            \"SELECT database_name, schema_name FROM collections\n292\t                 WHERE name = $1\n293\t                 ORDER BY CASE\n294\t                     WHEN database_name = 'default' AND schema_name = 'default' THEN 0\n295\t                     ELSE 1\n296\t                 END,\n297\t                 database_name,\n298\t                 schema_name\",\n299\t            &[&collection.as_str()],\n300\t        ))?;\n301\t        Ok(rows\n302\t            .iter()\n303\t            .map(|row| Namespace::new(row.get::<_, String>(0), row.get::<_, String>(1)))\n304\t            .collect())\n305\t    }\n306\t\n307\t    fn resolve_catalog_key(\n308\t        &self,\n309\t        collection: &CollectionId,\n310\t    ) -> Result<QualifiedCollectionId, AxonError> {\n311\t        let (namespace, bare_collection) = Namespace::parse(collection.as_str());\n312\t        if bare_collection != collection.as_str() {\n313\t            return Ok(QualifiedCollectionId::from_parts(\n314\t                &namespace,\n315\t                &CollectionId::new(bare_collection),\n316\t            ));\n317\t        }\n318\t\n319\t        let namespaces = self.registered_collection_namespaces(collection)?;\n320\t        match namespaces.as_slice() {\n321\t            [] => Ok(QualifiedCollectionId::from_parts(\n322\t                &Namespace::default_ns(),\n323\t                collection,\n324\t            )),\n325\t            [namespace] => Ok(QualifiedCollectionId::from_parts(namespace, collection)),\n326\t            _ => {\n327\t                let default_namespace = Namespace::default_ns();\n328\t                if namespaces.contains(&default_namespace) {\n329\t                    Ok(QualifiedCollectionId::from_parts(\n330\t                        &default_namespace,\n331\t                        collection,\n332\t                    ))\n333\t                } else {\n334\t                    Err(AxonError::InvalidArgument(format!(\n335\t                        \"collection '{}' exists in multiple namespaces; qualify the namespace\",\n336\t                        collection.as_str()\n337\t                    )))\n338\t                }\n339\t            }\n340\t        }\n341\t    }\n342\t\n343\t    fn namespace_collection_keys(\n344\t        &self,\n345\t        namespace: &Namespace,\n346\t    ) -> Result<Vec<QualifiedCollectionId>, AxonError> {\n347\t        let rows = self.block(self.client.query(\n348\t            \"SELECT name FROM collections\n349\t                 WHERE database_name = $1 AND schema_name = $2\n350\t                 ORDER BY name ASC\",\n351\t            &[&namespace.database, &namespace.schema],\n352\t        ))?;\n353\t        Ok(rows\n354\t            .iter()\n355\t            .map(|row| {\n356\t                QualifiedCollectionId::from_parts(\n357\t                    namespace,\n358\t                    &CollectionId::new(row.get::<_, String>(\"name\")),\n359\t                )\n360\t            })\n361\t            .collect())\n362\t    }\n363\t\n364\t    fn database_collection_keys(\n365\t        &self,\n366\t        database: &str,\n367\t    ) -> Result<Vec<QualifiedCollectionId>, AxonError> {\n368\t        let rows = self.block(self.client.query(\n369\t            \"SELECT schema_name, name FROM collections\n370\t                 WHERE database_name = $1\n371\t                 ORDER BY schema_name ASC, name ASC\",\n372\t            &[&database],\n373\t        ))?;\n374\t        Ok(rows\n375\t            .iter()\n376\t            .map(|row| {\n377\t                QualifiedCollectionId::from_parts(\n378\t                    &Namespace::new(database, row.get::<_, String>(\"schema_name\")),\n379\t                    &CollectionId::new(row.get::<_, String>(\"name\")),\n380\t                )\n381\t            })\n382\t            .collect())\n383\t    }\n384\t\n385\t    fn ensure_default_namespace(&self) -> Result<(), AxonError> {\n386\t        self.block(self.client.execute(\n387\t            \"INSERT INTO databases (name) VALUES ($1) ON CONFLICT DO NOTHING\",\n388\t            &[&DEFAULT_DATABASE],\n389\t        ))?;\n390\t        self.block(self.client.execute(\n391\t            \"INSERT INTO namespaces (database_name, name)\n392\t                 VALUES ($1, $2)\n393\t                 ON CONFLICT DO NOTHING\",\n394\t            &[&DEFAULT_DATABASE, &DEFAULT_SCHEMA],\n395\t        ))?;\n396\t        Ok(())\n397\t    }\n398\t\n399\t    fn row_to_entity(row: &tokio_postgres::Row) -> Result<Entity, AxonError> {\n400\t        let collection: String = row.get(\"collection\");\n401\t        let id: String = row.get(\"id\");\n402\t        let version: i64 = row.get(\"version\");\n403\t        let data: serde_json::Value = row.get(\"data\");\n404\t        Ok(Entity {\n405\t            collection: CollectionId::new(collection),\n406\t            id: EntityId::new(id),\n407\t            version: version as u64,\n408\t            data,\n409\t            created_at_ns: None,\n410\t            updated_at_ns: None,\n411\t            created_by: None,\n412\t            updated_by: None,\n413\t            schema_version: None,\n414\t            gate_results: Default::default(),\n415\t        })\n416\t    }\n417\t}\n418\t\n419\timpl StorageAdapter for PostgresStorageAdapter {\n420\t    fn resolve_collection_key(\n421\t        &self,\n422\t        collection: &CollectionId,\n423\t    ) -> Result<QualifiedCollectionId, AxonError> {\n424\t        self.resolve_catalog_key(collection)\n425\t    }\n426\t\n427\t    fn get(&self, collection: &CollectionId, id: &EntityId) -> Result<Option<Entity>, AxonError> {\n428\t        let key = self.resolve_catalog_key(collection)?;\n429\t        let rows = self.block(self.client.query(\n430\t            \"SELECT collection, id, version, data\n431\t                 FROM entities\n432\t                 WHERE collection = $1 AND database_name = $2 AND schema_name = $3 AND id = $4\",\n433\t            &[\n434\t                &key.collection.as_str(),\n435\t                &key.namespace.database,\n436\t                &key.namespace.schema,\n437\t                &id.as_str(),\n438\t            ],\n439\t        ))?;\n440\t\n441\t        match rows.first() {\n442\t            Some(row) => Ok(Some(Self::row_to_entity(row)?)),\n443\t            None => Ok(None),\n444\t        }\n445\t    }\n446\t\n447\t    fn put(&mut self, entity: Entity) -> Result<(), AxonError> {\n448\t        let key = self.resolve_catalog_key(&entity.collection)?;\n449\t        let data_json = serde_json::to_value(&entity.data)?;\n450\t        self.block(self.client.execute(\n451\t            \"INSERT INTO entities (collection, database_name, schema_name, id, version, data)\n452\t                 VALUES ($1, $2, $3, $4, $5, $6)\n453\t                 ON CONFLICT (database_name, schema_name, collection, id)\n454\t                 DO UPDATE SET version = $5, data = $6\",\n455\t            &[\n456\t                &key.collection.as_str(),\n457\t                &key.namespace.database,\n458\t                &key.namespace.schema,\n459\t                &entity.id.as_str(),\n460\t                &(entity.version as i64),\n461\t                &data_json,\n462\t            ],\n463\t        ))?;\n464\t        Ok(())\n465\t    }\n466\t\n467\t    fn delete(&mut self, collection: &CollectionId, id: &EntityId) -> Result<(), AxonError> {\n468\t        let key = self.res