 fn opening_legacy_db_unregister_collection_removes_stale_collection_view() {\n2177\t        let collection = CollectionId::new(\"legacy\");\n2178\t        let file = legacy_collection_views_db(&collection, \"# {{title}}\");\n2179\t        let path = file.path().to_string_lossy().into_owned();\n2180\t\n2181\t        let mut store = SqliteStorageAdapter::open(&path).expect(\"test operation should succeed\");\n2182\t        assert!(store\n2183\t            .get_collection_view(&collection)\n2184\t            .expect(\"test operation should succeed\")\n2185\t            .is_some());\n2186\t\n2187\t        store\n2188\t            .unregister_collection(&collection)\n2189\t            .expect(\"test operation should succeed\");\n2190\t\n2191\t        assert!(store\n2192\t            .get_collection_view(&collection)\n2193\t            .expect(\"test operation should succeed\")\n2194\t            .is_none());\n2195\t    }\n2196\t\n2197\t    #[test]\n2198\t    fn update_with_version_check_succeeds() {\n2199\t        let mut s = store();\n2200\t        s.put(entity(\"t-001\"))\n2201\t            .expect(\"test operation should succeed\");\n2202\t        let updated = s\n2203\t            .compare_and_swap(entity(\"t-001\"), 1)\n2204\t            .expect(\"test operation should succeed\");\n2205\t        assert_eq!(updated.version, 2);\n2206\t        let stored = s\n2207\t            .get(&tasks(), &EntityId::new(\"t-001\"))\n2208\t            .expect(\"test operation should succeed\")\n2209\t            .expect(\"test operation should succeed\");\n2210\t        assert_eq!(stored.version, 2);\n2211\t    }\n2212\t\n2213\t    #[test]\n2214\t    fn version_conflict_detected_and_rejected() {\n2215\t        let mut s = store();\n2216\t        s.put(entity(\"t-001\"))\n2217\t            .expect(\"test operation should succeed\");\n2218\t        let err = s\n2219\t            .compare_and_swap(entity(\"t-001\"), 99)\n2220\t            .expect_err(\"test operation should fail\");\n2221\t        assert!(\n2222\t            matches!(\n2223\t                err,\n2224\t                AxonError::ConflictingVersion {\n2225\t                    expected: 99,\n2226\t                    actual: 1,\n2227\t                    ..\n2228\t                }\n2229\t            ),\n2230\t            \"unexpected error: {err}\"\n2231\t        );\n2232\t        if let AxonError::ConflictingVersion { current_entity, .. } = err {\n2233\t            let ce =\n2234\t                current_entity.expect(\"current_entity must be present on wrong-version conflict\");\n2235\t            assert_eq!(ce.version, 1);\n2236\t        }\n2237\t    }\n2238\t\n2239\t    #[test]\n2240\t    fn compare_and_swap_missing_entity_rejected() {\n2241\t        let mut s = store();\n2242\t        let err = s\n2243\t            .compare_and_swap(entity(\"ghost\"), 1)\n2244\t            .expect_err(\"test operation should fail\");\n2245\t        assert!(\n2246\t            matches!(\n2247\t                err,\n2248\t                AxonError::ConflictingVersion {\n2249\t                    expected: 1,\n2250\t                    actual: 0,\n2251\t                    ..\n2252\t                }\n2253\t            ),\n2254\t            \"unexpected error: {err}\"\n2255\t        );\n2256\t        if let AxonError::ConflictingVersion { current_entity, .. } = err {\n2257\t            assert!(\n2258\t                current_entity.is_none(),\n2259\t                \"no entity for missing-entity conflict\"\n2260\t            );\n2261\t        }\n2262\t    }\n2263\t\n2264\t    #[test]\n2265\t    fn begin_commit_tx_persists_writes() {\n2266\t        let mut s = store();\n2267\t        s.begin_tx().expect(\"test operation should succeed\");\n2268\t        s.put(entity(\"t-001\"))\n2269\t            .expect(\"test operation should succeed\");\n2270\t        s.commit_tx().expect(\"test operation should succeed\");\n2271\t        assert!(s\n2272\t            .get(&tasks(), &EntityId::new(\"t-001\"))\n2273\t            .expect(\"test operation should succeed\")\n2274\t            .is_some());\n2275\t    }\n2276\t\n2277\t    #[test]\n2278\t    fn abort_tx_rolls_back_writes() {\n2279\t        let mut s = store();\n2280\t        s.put(entity(\"t-existing\"))\n2281\t            .expect(\"test operation should succeed\");\n2282\t\n2283\t        s.begin_tx().expect(\"test operation should succeed\");\n2284\t        s.put(entity(\"t-new\"))\n2285\t            .expect(\"test operation should succeed\");\n2286\t        s.delete(&tasks(), &EntityId::new(\"t-existing\"))\n2287\t            .expect(\"test operation should succeed\");\n2288\t        s.abort_tx().expect(\"test operation should succeed\");\n2289\t\n2290\t        assert!(s\n2291\t            .get(&tasks(), &EntityId::new(\"t-new\"))\n2292\t            .expect(\"test operation should succeed\")\n2293\t            .is_none());\n2294\t        assert!(s\n2295\t            .get(&tasks(), &EntityId::new(\"t-existing\"))\n2296\t            .expect(\"test operation should succeed\")\n2297\t            .is_some());\n2298\t    }\n2299\t\n2300\t    #[test]\n2301\t    fn begin_tx_rejects_nested_begin() {\n2302\t        let mut s = store();\n2303\t        s.begin_tx().expect(\"test operation should succeed\");\n2304\t        assert!(s.begin_tx().is_err());\n2305\t        s.abort_tx().expect(\"test operation should succeed\");\n2306\t    }\n2307\t\n2308\t    #[test]\n2309\t    fn commit_tx_requires_active_transaction() {\n2310\t        let mut s = store();\n2311\t        assert!(s.commit_tx().is_err());\n2312\t    }\n2313\t\n2314\t    #[test]\n2315\t    fn abort_tx_without_active_tx_is_noop() {\n2316\t        let mut s = store();\n2317\t        s.abort_tx().expect(\"test operation should succeed\");\n2318\t    }\n2319\t\n2320\t    // ── Schema persistence ───────────────────────────────────────────────────\n2321\t\n2322\t    #[test]\n2323\t    fn put_get_schema_roundtrip() {\n2324\t        use axon_schema::schema::CollectionSchema;\n2325\t        let mut s = store();\n2326\t        let col = tasks();\n2327\t        let schema = CollectionSchema {\n2328\t            collection: col.clone(),\n2329\t            description: Some(\"test schema\".into()),\n2330\t            version: 99, // ignored — auto-increment assigns v1\n2331\t            entity_schema: Some(json!({\"type\": \"object\"})),\n2332\t            link_types: Default::default(),\n2333\t            gates: Default::default(),\n2334\t            validation_rules: Default::default(),\n2335\t            indexes: Default::default(),\n2336\t            compound_indexes: Default::default(),\n2337\t            lifecycles: Default::default(),\n2338\t        };\n2339\t\n2340\t        s.put_schema(&schema)\n2341\t            .expect(\"test operation should succeed\");\n2342\t\n2343\t        let retrieved = s.get_schema(&col).expect(\"test operation should succeed\");\n2344\t        assert!(retrieved.is_some());\n2345\t        let retrieved = retrieved.expect(\"test operation should succeed\");\n2346\t        assert_eq!(retrieved.collection, col);\n2347\t        assert_eq!(retrieved.version, 1); // auto-incremented\n2348\t        assert_eq!(retrieved.description.as_deref(), Some(\"test schema\"));\n2349\t    }\n2350\t\n2351\t    #[test]\n2352\t    fn get_schema_missing_returns_none() {\n2353\t        let s = store();\n2354\t        assert!(s\n2355\t            .get_schema(&tasks())\n2356\t            .expect(\"test operation should succeed\")\n2357\t            .is_none());\n2358\t    }\n2359\t\n2360\t    #[test]\n2361\t    fn put_schema_overwrites_previous() {\n2362\t        use axon_schema::schema::CollectionSchema;\n2363\t        let mut s = store();\n2364\t        let col = tasks();\n2365\t\n2366\t        let v1 = CollectionSchema {\n2367\t            collection: col.clone(),\n2368\t            description: None,\n2369\t            version: 1,\n2370\t            entity_schema: None,\n2371\t            link_types: Default::default(),\n2372\t            gates: Default::default(),\n2373\t            validation_rules: Default::default(),\n2374\t            indexes: Default::default(),\n2375\t            compound_indexes: Default::default(),\n2376\t            lifecycles: Default::default(),\n2377\t        };\n2378\t        let v2 = CollectionSchema {\n2379\t            collection: col.clone(),\n2380\t            description: Some(\"v2\".into()),\n2381\t            version: 2,\n2382\t            entity_schema: None,\n2383\t            link_types: Default::default(),\n2384\t            gates: Default::default(),\n2385\t            validation_rules: Default::default(),\n2386\t            indexes: Default::default(),\n2387\t            compound_indexes: Default::default(),\n2388\t            lifecycles: Default::default(),\n2389\t        };\n2390\t\n2391\t        s.put_schema(&v1).expect(\"test operation should succeed\");\n2392\t        s.put_schema(&v2).expect(\"test operation should succeed\");\n2393\t\n2394\t        let retrieved = s\n2395\t            .get_schema(&col)\n2396\t            .expect(\"test operation should succeed\")\n2397\t            .expect(\"test operation should succeed\");\n2398\t        assert_eq!(\n2399\t            retrieved.version, 2,\n2400\t            \"second put_schema must overwrite the first\"\n2401\t        );\n2402\t    }\n2403\t\n2404\t    #[test]\n2405\t    fn delete_schema_removes_it() {\n2406\t        use axon_schema::schema::CollectionSchema;\n2407\t        let mut s = store();\n2408\t        let col = tasks();\n2409\t        let schema = CollectionSchema {\n2410\t            collection: col.clone(),\n2411\t            description: None,\n2412\t            version: 1,\n2413\t            entity_schema: None,\n2414\t            link_types: Default::default(),\n2415\t            gates: Default::default(),\n2416\t            validation_rules: Default::default(),\n2417\t            indexes: Default::default(),\n2418\t            compound_indexes: Default::default(),\n2419\t            lifecycles: Default::default(),\n2420\t        };\n2421\t\n2422\t        s.put_schema(&schema)\n2423\t            .expect(\"test operation should succeed\");\n2424\t        assert!(s\n2425\t            .get_schema(&col)\n2426\t            .expect(\"test operation should succeed\")\n2427\t            .is_some());\n2428\t\n2429\t        s.delete_schema(&col)\n2430\t            .expect(\"test operation should succeed\");\n2431\t        assert!(s\n2432\t            .get_schema(&col)\n2433\t            .expect(\"test operation should succeed\")\n2434\t            .is_none());\n2435\t    }\n2436\t\n2437\t    #[test]\n2438\t    fn qualified_schema_write_is_readable_via_bare_unique_collection() {\n2439\t        let mut s = store();\n2440\t        let qualified = CollectionId::new(\"prod.billing.invoices\");\n2441\t        let (billing, invoices) = register_unique_namespaced_collection(&mut s, &qualified);\n2442\t\n2443\t        let v1 = CollectionSchema {\n2444\t            collection: qualified.clone(),\n2445\t            description: Some(\"v1\".into()),\n2446\t            version: 99,\n2447\t            entity_schema: Some(\n2448\t                json!({\"type\": \"object\", \"properties\": {\"title\": {\"type\": \"string\"}}}),\n2449\t            ),\n2450\t            link_types: Default::default(),\n2451\t            gates: Default::default(),\n2452\t            validation_rules: Default::default(),\n2453\t            indexes: Default::default(),\n2454\t            compound_indexes: Default::default(),\n2455\t            lifecycles: Default::default(),\n2456\t        };\n2457\t        let v2 = CollectionSchema {\n2458\t            collection: qualified,\n2459\t            description: Some(\"v2\".into()),\n2460\t            version: 100,\n2461\t            entity_schema: Some(\n2462\t                json!({\"type\": \"object\", \"properties\": {\"amount\": {\"type\": \"number\"}}}),\n2463\t            ),\n2464\t            link_types: Default::default(),\n2465\t            gates: Default::default(),\n2466\t            validation_rules: Default::default(),\n2467\t            indexes: Default::default(),\n2468\t            compound_indexes: Default::default(),\n2469\t            lifecycles: Default::default(),\n2470\t        };\n2471\t\n2472\t        s.put_schema(&v1).expect(\"schema v1 put should succeed\");\n2473\t        s.put_schema(&v2).expect(\"schema v2 put should succeed\");\n2474\t\n2475\t        let stored_collections: Vec<String> = {\n2476\t            let conn = s.conn.lock().expect(\"lock\");\n2477\t            let mut stmt = conn\n2478\t                .prepare(\n2479\t                    \"SELECT collection FROM schema_versions\n2480\t                     WHERE database_name = ?1 AND schema_name = ?2\n2481\t                     ORDER BY version ASC\",\n2482\t                )\n2483\t                .expect(\"schema version query should prepare\");\n2484\t            stmt.query_map(\n2485\t                params![billing.database.as_str(), billing.schema.as_str()],\n2486\t                |row| row.get::<_, String>(0),\n2487\t            )\n2488\t            .expect(\"schema version query should succeed\")\n2489\t            .collect::<Result<Vec<_>, _>>()\n2490\t            .expect(\"schema version rows should decode\")\n2491\t        };\n2492\t        assert_eq!(\n2493\t            stored_collections,\n2494\t            vec![\"invoices\".to_string(), \"invoices\".to_string()]\n2495\t        );\n2496\t\n2497\t        let latest = s\n2498\t            .get_schema(&invoices)\n2499\t            .expect(\"latest schema lookup should succeed\")\n2500\t            .expect(\"latest schema should exist\");\n2501\t        assert_eq!(latest.collection, invoices);\n2502\t        assert_eq!(latest.version, 2);\n2503\t        assert_eq!(latest.description.as_deref(), Some(\"v2\"));\n2504\t\n2505\t        let version_one = s\n2506\t            .get_schema_version(&invoices, 1)\n2507\t            .expect(\"versioned schema lookup should succeed\")\n2508\t            .expect(\"schema version one should exist\");\n2509\t        assert_eq!(version_one.collection, invoices);\n2510\t        assert_eq!(version_one.description.as_deref(), Some(\"v1\"));\n2511\t\n2512\t        assert_eq!(\n2513\t            s.list_schema_versions(&invoices)\n2514\t                .expect(\"schema version list should succeed\")\n2515\t                .into_iter()\n2516\t                .map(|(version, _)| version)\n2517\t                .collect::<Vec<_>>(),\n2518\t            vec![1, 2]\n2519\t        );\n2520\t    }\n2521\t\n2522\t    #[test]\n2523\t    fn qualified_collection_view_write_is_readable_via_bare_unique_collection() {\n2524\t        let mut s = store();\n2525\t        let qualified = CollectionId::new(\"prod.billing.invoices\");\n2526\t        let (billing, invoices) = register_unique_namespaced_collection(&mut s, &qualified);\n2527\t\n2528\t        let stored = s\n2529\t            .put_collection_view(&CollectionView::new(qualified, \"# {{title}}\"))\n2530\t            .expect(\"qualified collection view put should succeed\");\n2531\t        assert_eq!(stored.collection, invoices);\n2532\t        assert_eq!(stored.version, 1);\n2533\t\n2534\t        let stored_collection: String = s\n2535\t            .conn\n2536\t            .lock()\n2537\t            .expect(\"lock\")\n2538\t            .query_row(\n2539\t                \"SELECT collection FROM collection_views\n2540\t                 WHERE database_name = ?1 AND schema_name = ?2\",\n2541\t                params![billing.database.as_str(), billing.schema.as_str()],\n2542\t                |row| row.get(0),\n2543\t            )\n2544\t            .expect(\"stored collection view lookup should succeed\");\n2545\t        assert_eq!(stored_collection, \"invoices\");\n2546\t\n2547\t        let retrieved = s\n2548\t            .get_collection_view(&invoices)\n2549\t            .expect(\"bare collection view lookup should succeed\")\n2550\t            .expect(\"collection view should exist\");\n2551\t        assert_eq!(retrieved.collection, invoices);\n2552\t        assert_eq!(retrieved.markdown_template, \"# {{title}}\");\n2553\t        assert_eq!(retrieved.version, 1);\n2554\t    }\n2555\t\n2556\t    // ── Audit co-location ────────────────────────────────────────────────────\n2557\t\n2558\t    #[test]\n2559\t    fn append_audit_entry_assigns_id_and_timestamp() {\n2560\t        use axon_audit::entry::{AuditEntry, MutationType};\n2561\t        use axon_core::id::{CollectionId, EntityId};\n2562\t        use serde_json::json;\n2563\t\n2564\t        let mut s = store();\n2565\t        let entry = AuditEntry::new(\n2566\t            CollectionId::new(\"tasks\"),\n2567\t            EntityId::new(\"t-001\"),\n2568\t            1,\n2569\t            MutationType::EntityCreate,\n2570\t            None,\n2571\t            Some(json!({\"title\": \"hello\"})),\n2572\t            Some(\"agent-1\".into()),\n2573\t        );\n2574\t        assert_eq!(entry.id, 0);\n2575\t        assert_eq!(entry.timestamp_ns, 0);\n2576\t\n2577\t        let stored = s\n2578\t            .append_audit_entry(entry)\n2579\t            .expect(\"test operation should succeed\");\n2580\t        assert_eq!(stored.id, 1, \"first entry gets id=1\");\n2581\t        assert!(stored.timestamp_ns > 0, \"timestamp_ns is assigned\");\n2582\t    }\n2583\t\n2584\t    #[test]\n2585\t    fn audit_entry_rolled_back_with_entity_on_abort() {\n2586\t        use axon_audit::entry::{AuditEntry, MutationType};\n2587\t        use axon_core::id::EntityId;\n2588\t        use serde_json::json;\n2589\t\n2590\t        let mut s = store();\n2591\t\n2592\t        // Begin a transaction, write an entity and an audit entry, then abort.\n2593\t        s.begin_tx().expect(\"test operation should succeed\");\n2594\t        s.put(entity(\"t-001\"))\n2595\t            .expect(\"test operation should succeed\");\n2596\t        let entry = AuditEntry::new(\n2597\t            tasks(),\n2598\t            EntityId::new(\"t-001\"),\n2599\t            1,\n2600\t            MutationType::EntityCreate,\n2601\t            None,\n2602\t            Some(json!({\"title\": \"t-001\"})),\n2603\t            None,\n2604\t        );\n2605\t        s.append_audit_entry(entry)\n2606\t            .expect(\"test operation should succeed\");\n2607\t        s.abort_tx().expect(\"test operation should succeed\");\n2608\t\n2609\t        // Entity must be absent.\n2610\t        assert!(s\n2611\t            .get(&tasks(), &EntityId::new(\"t-001\"))\n2612\t            .expect(\"test operation should succeed\")\n2613\t            .is_none());\n2614\t\n2615\t        // Audit entry must also be absent (rolled back with the transaction).\n2616\t        let count: i64 = s\n2617\t            .conn\n2618\t            .lock()\n2619\t            .expect(\"lock\")\n2620\t            .query_row(\"SELECT COUNT(*) FROM audit_log\", [], |r| r.get(0))\n2621\t            .expect(\"test operation should succeed\");\n2622\t        assert_eq!(count, 0, \"audit entry must be rolled back with the entity\");\n2623\t    }\n2624\t\n2625\t    #[test]\n2626\t    fn audit_entry_persists_with_entity_on_commit() {\n2627\t        use axon_audit::entry::{AuditEntry, MutationType};\n2628\t        use axon_core::id::EntityId;\n2629\t        use serde_json::json;\n2630\t\n2631\t        let mut s = store();\n2632\t\n2633\t        s.begin_tx().expect(\"test operation should succeed\");\n2634\t        s.put(entity(\"t-001\"))\n2635\t            .expect(\"test operation should succeed\");\n2636\t        let entry = AuditEntry::new(\n2637\t            tasks(),\n2638\t            EntityId::new(\"t-001\"),\n2639\t            1,\n2640\t            MutationType::EntityCreate,\n2641\t            None,\n2642\t            Some(json!({\"title\": \"t-001\"})),\n2643\t            Some(\"tester\".into()),\n2644\t        );\n2645\t        s.append_audit_entry(entry)\n2646\t            .expect(\"test operation should succeed\");\n2647\t        s.commit_tx().expect(\"test operation should succeed\");\n2648\t\n2649\t        // Entity must be present.\n2650\t        assert!(s\n2651\t            .get(&tasks(), &EntityId::new(\"t-001\"))\n2652\t            .expect(\"test operation should succeed\")\n2653\t            .is_some());\n2654\t\n2655\t        // Audit entry must also be present.\n2656\t        let count: i64 = s\n2657\t            .conn\n2658\t            .lock()\n2659\t            .expect(\"lock\")\n2660\t            .query_row(\"SELECT COUNT(*) FROM audit_log\", [], |r| r.get(0))\n2661\t            .expect(\"test operation should succeed\");\n2662\t        assert_eq!(\n2663\t            count, 1,\n2664\t            \"audit entry must persist when transaction commits\"\n2665\t        );\n2666\t    }\n2667\t\n2668\t    #[test]\n2669\t    fn two_part_collection_names_resolve_to_default_database_schema() {\n2670\t        let mut s = store();\n2671\t        let billing = Namespace::new(\"default\", \"billing\");\n2672\t        let invoices = CollectionId::new(\"invoices\");\n2673\t        let schema_qualified = CollectionId::new(\"billing.invoices\");\n2674\t        let fully_qualified = CollectionId::new(\"default.billing.invoices\");\n2675\t        let entity_id = EntityId::new(\"inv-001\");\n2676\t\n2677\t        s.create_namespace(&billing)\n2678\t            .expect(\"billing namespace create should succeed\");\n2679\t        s.register_collection_in_namespace(&invoices, &billing)\n2680\t            .expect(\"billing collection register should succeed\");\n2681\t        s.put(Entity::new(\n2682\t            schema_qualified.clone(),\n2683\t            entity_id.clone(),\n2684\t            json!({\"scope\": \"billing\"}),\n2685\t        ))\n2686\t        .expect(\"two-part entity put should succeed\");\n2687\t\n2688\t        assert_eq!(\n2689\t            s.get(&schema_qualified, &entity_id)\n2690\t                .expect(\"two-part get should succeed\")\n2691\t  