type cancelOnMatchWriter struct {
	bytes.Buffer
	match  string
	cancel context.CancelFunc
	once   sync.Once
}

func (w *cancelOnMatchWriter) Write(p []byte) (int, error) {
	n, err := w.Buffer.Write(p)
	if w.cancel != nil && strings.Contains(string(p), w.match) {
		w.once.Do(w.cancel)
	}
	return n, err
}

