func TestWorkRetryEscalation_NiflheimEvidence_OnlySemanticFailuresRaiseMinPower(t *testing.T) {
	t.Run("semantic no-changes bad attempt raises min power", func(t *testing.T) {
		store := bead.NewStore(t.TempDir())
		require.NoError(t, store.Init(context.Background()))

		b := &bead.Bead{ID: "ddx-niflheim-semantic", Title: "Niflheim semantic retry escalation"}
		require.NoError(t, store.Create(context.Background(), b))

		var floorCalls int32
		noChanges := &agenttry.NoChangesOutcome{
			Action:          agenttry.NoChangesActionBadAttemptNoCooldown,
			Reason:          "semantic acceptance failure",
			SuggestedAction: "retry with a stronger model",
		}
		require.NoError(t, applyNoChangesBadAttemptEscalation(store, b.ID, "worker", noChanges, 70, func(actualPower int) (int, error) {
			atomic.AddInt32(&floorCalls, 1)
			return actualPower + 3, nil
		}))

		assert.Equal(t, int32(1), atomic.LoadInt32(&floorCalls))
		got, err := store.Get(context.Background(), b.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusOpen, got.Status)
		assert.EqualValues(t, 73, got.Extra[executeLoopNoChangesNextMinPowerKey])
	})

	t.Run("pre-claim system warning does not raise min power", func(t *testing.T) {
		store, first, second := newExecuteLoopTestStore(t)

		var floorCalls int32
		var execCalls int32
		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				atomic.AddInt32(&execCalls, 1)
				return ExecuteBeadReport{
					BeadID:    beadID,
					Status:    ExecuteBeadStatusSuccess,
					ResultRev: "rev-" + beadID,
				}, nil
			}),
			EscalationNextFloor: func(actualPower int) (int, error) {
				atomic.AddInt32(&floorCalls, 1)
				return actualPower + 1, nil
			},
		}

		var eventSink bytes.Buffer
		cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
			Mode:                        executeloop.ModeDrain,
			EventSink:                   &eventSink,
			NoReview:                    true,
			PreClaimWarnRepeatThreshold: 2,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				return PreClaimIntakeResult{
					Outcome: PreClaimIntakeError,
					Reason:  "system_unready",
					Detail:  "generated DDx artifact dirt at .ddx/harness-sessions/session-system-unready.json",
				}, nil
			},
		})
		require.NoError(t, err)
		require.NotNil(t, result)
		assert.Equal(t, int32(1), atomic.LoadInt32(&execCalls))
		assert.Equal(t, int32(0), atomic.LoadInt32(&floorCalls), "pre-claim warnings must not consult the min-power ladder")
		require.NotNil(t, result.OperatorAttention)
		assert.Equal(t, "preclaim_warn_repeated", result.OperatorAttention.Reason)
		assert.Equal(t, second.ID, result.OperatorAttention.BeadID)

		gotFirst, err := store.Get(context.Background(), first.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusClosed, gotFirst.Status)

		gotSecond, err := store.Get(context.Background(), second.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusOpen, gotSecond.Status)

		var sawEscalation bool
		for _, line := range strings.Split(strings.TrimSpace(eventSink.String()), "\n") {
			if strings.TrimSpace(line) == "" {
				continue
			}
			var entry map[string]any
			require.NoError(t, json.Unmarshal([]byte(line), &entry))
			if entry["type"] != "loop.operator_attention" {
				continue
			}
			data, ok := entry["data"].(map[string]any)
			require.True(t, ok)
			if data["reason"] == "preclaim_warn_repeated" {
				sawEscalation = true
				assert.Equal(t, "generated DDx artifact dirt at .ddx/harness-sessions/session-system-unready.json", data["example_detail"])
			}
		}
		assert.True(t, sawEscalation, "the repeated pre-claim warning must emit operator attention")
	})

	t.Run("land coordination does not raise min power", func(t *testing.T) {
		store, first, _ := newExecuteLoopTestStore(t)

		var floorCalls int32
		worker := &ExecuteBeadWorker{
			Store: store,
			EscalationNextFloor: func(actualPower int) (int, error) {
				atomic.AddInt32(&floorCalls, 1)
				return actualPower + 1, nil
			},
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				return ExecuteBeadReport{
					BeadID:        beadID,
					Status:        ExecuteBeadStatusLandRetry,
					Detail:        "land coordination retry: generated DDx artifact dirt",
					BaseRev:       "base-land",
					ResultRev:     "result-land",
					OutcomeReason: FailureModeLandRetry,
				}, nil
			}),
		}

		cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true, TargetBeadID: first.ID})
		require.NoError(t, err)
		require.NotNil(t, result)
		assert.Equal(t, int32(0), atomic.LoadInt32(&floorCalls), "land coordination must not consult the min-power ladder")

		got, err := store.Get(context.Background(), first.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusOpen, got.Status)
	})

	t.Run("decomposed parent does not raise min power", func(t *testing.T) {
		store := bead.NewStore(t.TempDir())
		require.NoError(t, store.Init(context.Background()))

		parent := &bead.Bead{ID: "ddx-niflheim-retry-parent", Title: "Niflheim decomposed parent retry"}
		require.NoError(t, store.Create(context.Background(), parent))

		var execCalls int32
		var floorCalls int32
		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				atomic.AddInt32(&execCalls, 1)
				return ExecuteBeadReport{
					BeadID:             beadID,
					Status:             ExecuteBeadStatusExecutionFailed,
					Detail:             mixedCommitAndNoChangesRationaleReason,
					BaseRev:            "base-retry",
					ResultRev:          "result-retry",
					ActualPower:        50,
					RequestedProfile:   "standard",
					NoChangesRationale: "status: open\norchestrator_action: decompose\nreason: parent already split into child beads",
				}, nil
			}),
			EscalationNextFloor: func(actualPower int) (int, error) {
				atomic.AddInt32(&floorCalls, 1)
				return actualPower + 10, nil
			},
		}

		cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", MaxDecompositionDepth: 3}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
			Once:         true,
			TargetBeadID: parent.ID,
			PostAttemptDecompositionHook: func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
				return niflheimDecomposedParentFixture(), nil
			},
		})
		require.NoError(t, err)
		require.NotNil(t, result)
		assert.Equal(t, int32(1), atomic.LoadInt32(&execCalls))
		assert.Equal(t, int32(0), atomic.LoadInt32(&floorCalls), "decomposed parents must not consult the min-power ladder")

		got, err := store.Get(context.Background(), parent.ID)
		require.NoError(t, err)
		assert.Equal(t, false, got.Extra[bead.ExtraExecutionElig])
		assert.NotContains(t, got.Extra, executeLoopNoChangesNextMinPowerKey)
	})

	t.Run("dirty generated DDx evidence does not raise min power", func(t *testing.T) {
		store, first, _ := newExecuteLoopTestStore(t)

		var floorCalls int32

		var floorCalls int32
		var execCalls int32
		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				atomic.AddInt32(&execCalls, 1)
				t.Fatalf("executor must not run when the project root is dirty: %s", beadID)
				return ExecuteBeadReport{}, nil
			}),
			EscalationNextFloor: func(actualPower int) (int, error) {
				atomic.AddInt32(&floorCalls, 1)
				return actualPower + 1, nil
			},
		}

		cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
			Mode:         executeloop.ModeDrain,
			ProjectRoot:   t.TempDir(),
			ProjectRootDirtyCheck: func(projectRoot string) []string {
				return []string{".ddx/harness-sessions/session-system-unready.json"}
			},
		})
		require.NoError(t, err)
		require.NotNil(t, result)
		assert.Equal(t, int32(0), atomic.LoadInt32(&execCalls))
		assert.Equal(t, int32(0), atomic.LoadInt32(&floorCalls), "dirty generated DDx evidence must not consult the min-power ladder")
		require.NotNil(t, result.OperatorAttention)
		assert.Equal(t, "dirty_project_root", result.OperatorAttention.Reason)
		assert.Contains(t, result.OperatorAttention.DirtyPaths, ".ddx/harness-sessions/session-system-unready.json")
		assert.Equal(t, bead.StatusOpen, func() string {
			got, err := store.Get(context.Background(), first.ID)
			require.NoError(t, err)
			return got.Status
		}())
	})
}

